  1→/**
  2→ * Learning Diagnosis: Observation Clustering, Root Cause Classification, and Learning Proposals
  3→ *
  4→ * Groups open observations by embedding similarity into clusters,
  5→ * checks if active learnings already cover each cluster pattern,
  6→ * classifies root causes via LLM structured output, and proposes learnings.
  7→ *
  8→ * Pure query functions + pipeline composition. IO at boundaries only.
  9→ *
 10→ * Step 01-01: Clustering + coverage check
 11→ * Step 01-02: Root cause classification with LLM structured output
 12→ * Step 01-03: Learning proposer + graph scan integration
 13→ */
 14→
 15→import { RecordId, type Surreal } from "surrealdb";
 16→import { generateObject, type LanguageModel } from "ai";
 17→import { logError, logInfo } from "../http/observability";
 18→import { rootCauseSchema, type RootCauseClassification } from "./schemas";
 19→import { OBSERVER_IDENTITY } from "../agents/observer/prompt";
 20→import { suggestLearning } from "../learning/detector";
 21→import { createObservation } from "../observation/queries";
 22→import { createEmbeddingVector } from "../graph/embeddings";
 23→import type { CreateLearningInput } from "../learning/types";
 24→import type { embed } from "ai";
 25→
 26→type EmbeddingModel = Parameters<typeof embed>[0]["model"];
 27→
 28→// ---------------------------------------------------------------------------
 29→// Types
 30→// ---------------------------------------------------------------------------
 31→
 32→export type ObservationWithEmbedding = {
 33→  id: string;
 34→  text: string;
 35→  severity: string;
 36→  embedding: number[];
 37→  entityRefs: string[];
 38→};
 39→
 40→export type ObservationCluster = {
 41→  observations: Array<{ id: string; text: string; severity: string; entityRefs: string[] }>;
 42→  representativeText: string;
 43→  clusterSize: number;
 44→};
 45→
 46→export type CoverageCheckResult =
 47→  | { covered: false }
 48→  | { covered: true; matchedLearningText: string; similarity: number };
 49→
 50→export type DiagnosticResult = {
 51→  learning_proposals_created: number;
 52→  coverage_skips: number;
 53→  clusters_found: number;
 54→};
 55→
 56→// ---------------------------------------------------------------------------
 57→// Configuration
 58→// ---------------------------------------------------------------------------
 59→
 60→const CLUSTER_SIMILARITY_THRESHOLD = 0.75;
 61→const MINIMUM_CLUSTER_SIZE = 3;
 62→const TIME_WINDOW_DAYS = 14;
 63→const COVERAGE_SIMILARITY_THRESHOLD = 0.80;
 64→const DISMISSED_PATTERN_SIMILARITY_THRESHOLD = 0.75;
 65→
 66→// ---------------------------------------------------------------------------
 67→// Observation query (IO boundary)
 68→// ---------------------------------------------------------------------------
 69→
 70→/**
 71→ * Queries open/acknowledged observations from the past 14 days with embeddings.
 72→ * Uses two-step KNN pattern per SurrealDB HNSW+WHERE bug.
 73→ */
 74→export async function queryRecentObservationsWithEmbeddings(
 75→  surreal: Surreal,
 76→  workspaceRecord: RecordId<"workspace", string>,
 77→): Promise<ObservationWithEmbedding[]> {
 78→  const cutoff = new Date(Date.now() - TIME_WINDOW_DAYS * 24 * 60 * 60 * 1000);
 79→
 80→  const [rows] = await surreal.query<[Array<{
 81→    id: RecordId<"observation">;
 82→    text: string;
 83→    severity: string;
 84→    embedding: number[];
 85→    entity_refs: string[];
 86→    created_at: string;
 87→  }>]>(
 88→    `SELECT id, text, severity, embedding, created_at,
 89→            ->observes->task.id AS entity_refs
 90→     FROM observation
 91→     WHERE workspace = $ws
 92→       AND status IN ["open", "acknowledged"]
 93→       AND created_at > $cutoff
 94→       AND embedding IS NOT NONE
 95→     ORDER BY created_at DESC
 96→     LIMIT 200;`,
 97→    { ws: workspaceRecord, cutoff },
 98→  );
 99→
100→  return (rows ?? []).map((row) => ({
101→    id: row.id.id as string,
102→    text: row.text,
103→    severity: row.severity,
104→    embedding: row.embedding,
105→    entityRefs: (row.entity_refs ?? []).map((ref) =>
106→      typeof ref === "object" && ref !== null && "id" in ref
107→        ? `task:${(ref as RecordId).id as string}`
108→        : String(ref),
109→    ),
110→  }));
111→}
112→
113→// ---------------------------------------------------------------------------
114→// Pure clustering (no IO)
115→// ---------------------------------------------------------------------------
116→
117→/**
118→ * Computes cosine similarity between two vectors.
119→ */
120→function cosineSimilarity(vectorA: number[], vectorB: number[]): number {
121→  let dotProduct = 0;
122→  let normA = 0;
123→  let normB = 0;
124→
125→  for (let i = 0; i < vectorA.length; i++) {
126→    dotProduct += vectorA[i] * vectorB[i];
127→    normA += vectorA[i] * vectorA[i];
128→    normB += vectorB[i] * vectorB[i];
129→  }
130→
131→  const denominator = Math.sqrt(normA) * Math.sqrt(normB);
132→  if (denominator === 0) return 0;
133→  return dotProduct / denominator;
134→}
135→
136→/**
137→ * Clusters observations by pairwise embedding similarity using single-linkage.
138→ *
139→ * Algorithm:
140→ * 1. Build adjacency: observation A is neighbor of B if similarity > threshold
141→ * 2. Connected components via BFS form clusters
142→ * 3. Filter clusters by minimum size
143→ *
144→ * Pure function -- no IO.
145→ */
146→export function clusterObservationsBySimilarity(
147→  observations: ObservationWithEmbedding[],
148→  similarityThreshold: number = CLUSTER_SIMILARITY_THRESHOLD,
149→  minimumClusterSize: number = MINIMUM_CLUSTER_SIZE,
150→): ObservationCluster[] {
151→  if (observations.length < minimumClusterSize) return [];
152→
153→  // Build adjacency list
154→  const adjacency = new Map<number, Set<number>>();
155→  for (let i = 0; i < observations.length; i++) {
156→    adjacency.set(i, new Set());
157→  }
158→
159→  for (let i = 0; i < observations.length; i++) {
160→    for (let j = i + 1; j < observations.length; j++) {
161→      const similarity = cosineSimilarity(
162→        observations[i].embedding,
163→        observations[j].embedding,
164→      );
165→      if (similarity > similarityThreshold) {
166→        adjacency.get(i)!.add(j);
167→        adjacency.get(j)!.add(i);
168→      }
169→    }
170→  }
171→
172→  // BFS to find connected components
173→  const visited = new Set<number>();
174→  const clusters: ObservationCluster[] = [];
175→
176→  for (let i = 0; i < observations.length; i++) {
177→    if (visited.has(i)) continue;
178→
179→    const component: number[] = [];
180→    const queue = [i];
181→    visited.add(i);
182→
183→    while (queue.length > 0) {
184→      const current = queue.shift()!;
185→      component.push(current);
186→
187→      for (const neighbor of adjacency.get(current)!) {
188→        if (!visited.has(neighbor)) {
189→          visited.add(neighbor);
190→          queue.push(neighbor);
191→        }
192→      }
193→    }
194→
195→    if (component.length >= minimumClusterSize) {
196→      const clusterObservations = component.map((idx) => ({
197→        id: observations[idx].id,
198→        text: observations[idx].text,
199→        severity: observations[idx].severity,
200→        entityRefs: observations[idx].entityRefs,
201→      }));
202→
203→      // Representative text: the observation with highest average similarity to others in cluster
204→      const representativeIndex = pickRepresentativeIndex(component, observations);
205→
206→      clusters.push({
207→        observations: clusterObservations,
208→        representativeText: observations[representativeIndex].text,
209→        clusterSize: component.length,
210→      });
211→    }
212→  }
213→
214→  return clusters;
215→}
216→
217→/**
218→ * Picks the observation with highest average similarity to other cluster members.
219→ * Pure function.
220→ */
221→function pickRepresentativeIndex(
222→  componentIndices: number[],
223→  observations: ObservationWithEmbedding[],
224→): number {
225→  let bestIndex = componentIndices[0];
226→  let bestAvgSimilarity = -1;
227→
228→  for (const i of componentIndices) {
229→    let totalSimilarity = 0;
230→    for (const j of componentIndices) {
231→      if (i !== j) {
232→        totalSimilarity += cosineSimilarity(
233→          observations[i].embedding,
234→          observations[j].embedding,
235→        );
236→      }
237→    }
238→    const avgSimilarity = totalSimilarity / (componentIndices.length - 1);
239→    if (avgSimilarity > bestAvgSimilarity) {
240→      bestAvgSimilarity = avgSimilarity;
241→      bestIndex = i;
242→    }
243→  }
244→
245→  return bestIndex;
246→}
247→
248→// ---------------------------------------------------------------------------
249→// Coverage check (IO boundary -- KNN query)
250→// ---------------------------------------------------------------------------
251→
252→/**
253→ * Checks if an active learning already covers the cluster pattern.
254→ * Uses two-step KNN pattern per SurrealDB HNSW+WHERE bug.
255→ *
256→ * Returns covered=true if any active learning has similarity > 0.80
257→ * to the cluster's representative observation embedding.
258→ */
259→export async function checkCoverageAgainstActiveLearnings(
260→  surreal: Surreal,
261→  workspaceRecord: RecordId<"workspace", string>,
262→  clusterEmbedding: number[],
263→): Promise<CoverageCheckResult> {
264→  // Two-step KNN: LET returns null result, SELECT returns actual matches
265→  // query() returns array of statement results: [LET result, SELECT result]
266→  const results = await surreal
267→    .query<[undefined, Array<{ text: string; similarity: number }>]>(
268→      [
269→        "LET $candidates = SELECT id, text, workspace, status,",
270→        "vector::similarity::cosine(embedding, $embedding) AS similarity",
271→        "FROM learning WHERE embedding <|10, COSINE|> $embedding;",
272→        "SELECT text, similarity FROM $candidates",
273→        `WHERE workspace = $ws AND status = "active" AND similarity > ${COVERAGE_SIMILARITY_THRESHOLD}`,
274→        "ORDER BY similarity DESC LIMIT 1;",
275→      ].join("\n"),
276→      {
277→        embedding: clusterEmbedding,
278→        ws: workspaceRecord,
279→      },
280→    );
281→
282→  // LET is index 0 (undefined), SELECT is index 1
283→  const matches = results[1] ?? [];
284→  const match = matches[0];
285→  if (match) {
286→    return { covered: true, matchedLearningText: match.text, similarity: match.similarity };
287→  }
288→
289→  // Fallback: brute-force scan when HNSW index hasn't indexed recent inserts.
290→  // Queries all active learnings with embeddings and computes similarity in-app.
291→  const [activeLearnings] = await surreal.query<[Array<{ text: string; embedding: number[] }>]>(
292→    `SELECT text, embedding FROM learning
293→     WHERE workspace = $ws
294→       AND status = "active"
295→       AND embedding IS NOT NONE;`,
296→    { ws: workspaceRecord },
297→  );
298→
299→  logInfo("observer.learning.coverage_fallback", "Fallback coverage check", {
300→    activeLearningsCount: (activeLearnings ?? []).length,
301→    workspaceId: workspaceRecord.id,
302→  });
303→
304→  for (const learning of activeLearnings ?? []) {
305→    const similarity = cosineSimilarity(clusterEmbedding, learning.embedding);
306→    if (similarity > COVERAGE_SIMILARITY_THRESHOLD) {
307→      return { covered: true, matchedLearningText: learning.text, similarity };
308→    }
309→  }
310→
311→  return { covered: false };
312→}
313→
314→// ---------------------------------------------------------------------------
315→// Dismissed learning check (IO boundary -- prevents re-suggestion)
316→// ---------------------------------------------------------------------------
317→
318→/**
319→ * Checks if a dismissed learning already covers the cluster pattern.
320→ * Uses the representative observation embedding against dismissed learnings.
321→ * Threshold is lower than the dismissed re-suggestion gate (0.85) because
322→ * we compare observation text embeddings (not proposed learning text).
323→ *
324→ * Two-step KNN pattern per SurrealDB HNSW+WHERE bug, with brute-force fallback.
325→ */
326→export async function checkDismissedLearningForCluster(
327→  surreal: Surreal,
328→  workspaceRecord: RecordId<"workspace", string>,
329→  clusterEmbedding: number[],
330→): Promise<CoverageCheckResult> {
331→  const results = await surreal
332→    .query<[undefined, Array<{ text: string; similarity: number }>]>(
333→      [
334→        "LET $candidates = SELECT id, text, workspace, status,",
335→        "vector::similarity::cosine(embedding, $embedding) AS similarity",
336→        "FROM learning WHERE embedding <|10, COSINE|> $embedding;",
337→        "SELECT text, similarity FROM $candidates",
338→        `WHERE workspace = $ws AND status = "dismissed" AND similarity > ${DISMISSED_PATTERN_SIMILARITY_THRESHOLD}`,
339→        "ORDER BY similarity DESC LIMIT 1;",
340→      ].join("\n"),
341→      {
342→        embedding: clusterEmbedding,
343→        ws: workspaceRecord,
344→      },
345→    );
346→
347→  const matches = results[1] ?? [];
348→  const match = matches[0];
349→  if (match) {
350→    return { covered: true, matchedLearningText: match.text, similarity: match.similarity };
351→  }
352→
353→  // Brute-force fallback when HNSW index hasn't indexed recent inserts
354→  const [dismissedLearnings] = await surreal.query<[Array<{ text: string; embedding: number[] }>]>(
355→    `SELECT text, embedding FROM learning
356→     WHERE workspace = $ws
357→       AND status = "dismissed"
358→       AND embedding IS NOT NONE;`,
359→    { ws: workspaceRecord },
360→  );
361→
362→  for (const learning of dismissedLearnings ?? []) {
363→    const similarity = cosineSimilarity(clusterEmbedding, learning.embedding);
364→    if (similarity > DISMISSED_PATTERN_SIMILARITY_THRESHOLD) {
365→      return { covered: true, matchedLearningText: learning.text, similarity };
366→    }
367→  }
368→
369→  return { covered: false };
370→}
371→
372→// ---------------------------------------------------------------------------
373→// Root cause classification (LLM structured output)
374→// ---------------------------------------------------------------------------
375→
376→const CONFIDENCE_THRESHOLD = 0.70;
377→const CLASSIFICATION_TIMEOUT_MS = 30_000;
378→
379→/**
380→ * Builds the LLM prompt for root cause classification.
381→ * Pure function -- formats cluster and context into prompt text.
382→ */
383→function buildClassificationPrompt(
384→  cluster: ObservationCluster,
385→  existingLearnings: string[],
386→): string {
387→  const observationQuotes = cluster.observations
388→    .map((obs, i) => `  ${i + 1}. [${obs.severity}] "${obs.text}"`)
389→    .join("\n");
390→
391→  const entityRefsList = [
392→    ...new Set(cluster.observations.flatMap((obs) => obs.entityRefs)),
393→  ];
394→  const entityRefsText = entityRefsList.length > 0
395→    ? entityRefsList.map((ref) => `  - ${ref}`).join("\n")
396→    : "  No linked entities.";
397→
398→  const learningsText = existingLearnings.length > 0
399→    ? existingLearnings.map((l, i) => `  ${i + 1}. ${l}`).join("\n")
400→    : "  No active learnings.";
401→
402→  return `You are performing root cause analysis on a recurring pattern detected in the workspace.
403→
404→## Pattern Detected
405→Representative text: "${cluster.representativeText}"
406→
407→Observation quotes (${cluster.clusterSize} occurrences):
408→${observationQuotes}
409→
410→## Related Entities
411→${entityRefsText}
412→
413→## Existing Active Learnings
414→${learningsText}
415→
416→## Classification Instructions
417→Determine WHY this pattern keeps recurring:
418→
419→1. Policy Failure: The governance rules allowed something they shouldn't.
420→   -> Propose a constraint that tightens the boundary.
421→
422→2. Context Failure: The agent lacked information it needed to act correctly.
423→   -> Propose an instruction that injects the missing context.
424→
425→3. Behavioral Drift: The agent had the information but didn't apply it.
426→   -> Propose a constraint that reinforces the expected behavior.
427→
428→Set should_propose_learning to true ONLY if:
429→- confidence >= 0.70
430→- You have high conviction in both the category AND the proposed text
431→- The proposed learning is specific enough to be actionable
432→
433→Set should_propose_learning to false if:
434→- The root cause is ambiguous or could fit multiple categories
435→- The proposed learning text is too generic ("be more careful")
436→- The evidence is insufficient to justify a permanent behavioral rule
437→
438→For proposed_learning_type, choose based on the fix needed:
439→- "constraint" for must-follow rules (policy fixes, behavioral reinforcement)
440→- "instruction" for conditional guidance (context injection, situational awareness)
441→
442→In evidence_refs, list the observation IDs in table:id format (e.g. observation:uuid).
443→In target_agents, list the agent types that should receive this learning.`;
444→}
445→
446→/**
447→ * Classifies the root cause of an observation cluster using LLM structured output.
448→ * Returns undefined on any failure (timeout, rate limit, invalid output).
449→ */
450→export async function classifyRootCause(
451→  model: LanguageModel,
452→  cluster: ObservationCluster,
453→  existingLearnings: string[],
454→): Promise<RootCauseClassification | undefined> {
455→  const start = Date.now();
456→
457→  try {
458→    const prompt = buildClassificationPrompt(cluster, existingLearnings);
459→
460→    const result = await generateObject({
461→      model,
462→      system: OBSERVER_IDENTITY,
463→      schema: rootCauseSchema,
464→      prompt,
465→      abortSignal: AbortSignal.timeout(CLASSIFICATION_TIMEOUT_MS),
466→    });
467→
468→    const latencyMs = Date.now() - start;
469→    logInfo("observer.llm.root_cause", "Root cause classification completed", {
470→      latencyMs,
471→      category: result.object.category,
472→      confidence: result.object.confidence,
473→      shouldPropose: result.object.should_propose_learning,
474→    });
475→
476→    return result.object;
477→  } catch (error) {
478→    const latencyMs = Date.now() - start;
479→    logError("observer.llm.root_cause_error", "Root cause classification failed", {
480→      error,
481→      latencyMs,
482→    });
483→    return undefined;
484→  }
485→}
486→
487→// ---------------------------------------------------------------------------
488→// Dual gate: decide whether to propose learning or create observation
489→// ---------------------------------------------------------------------------
490→
491→/**
492→ * Applies the dual gate: should_propose_learning AND confidence >= threshold.
493→ * Pure function -- no IO.
494→ */
495→function shouldProposeLearning(classification: RootCauseClassification): boolean {
496→  return classification.should_propose_learning && classification.confidence >= CONFIDENCE_THRESHOLD;
497→}
498→
499→/**
500→ * Maps a root cause classification to a CreateLearningInput.
501→ * Pure function -- no IO.
502→ */
503→function rootCauseToLearningInput(
504→  classification: RootCauseClassification,
505→  cluster: ObservationCluster,
506→): CreateLearningInput {
507→  return {
508→    text: classification.proposed_learning_text,
509→    learningType: classification.proposed_learning_type,
510→    source: "agent",
511→    suggestedBy: "observer",
512→    patternConfidence: classification.confidence,
513→    targetAgents: classification.target_agents,
514→    evidenceIds: cluster.observations.map((obs) => ({
515→      table: "observation" as const,
516→      id: obs.id,
517→    })),
518→  };
519→}
520→
521→// ---------------------------------------------------------------------------
522→// Query existing active learnings for classification context
523→// ---------------------------------------------------------------------------
524→
525→async function queryActiveLearningTexts(
526→  surreal: Surreal,
527→  workspaceRecord: RecordId<"workspace", string>,
528→): Promise<string[]> {
529→  const [rows] = await surreal.query<[Array<{ text: string; created_at: string }>]>(
530→    `SELECT text, created_at FROM learning
531→     WHERE workspace = $ws AND status = "active"
532→     ORDER BY created_at DESC
533→     LIMIT 20;`,
534→    { ws: workspaceRecord },
535→  );
536→  return (rows ?? []).map((r) => r.text);
537→}
538→
539→// ---------------------------------------------------------------------------
540→// Process a single uncovered cluster: classify and propose or observe
541→// ---------------------------------------------------------------------------
542→
543→async function processUncoveredCluster(
544→  surreal: Surreal,
545→  workspaceRecord: RecordId<"workspace", string>,
546→  model: LanguageModel,
547→  cluster: ObservationCluster,
548→  existingLearnings: string[],
549→  embeddingModel?: EmbeddingModel,
550→  embeddingDimension?: number,
551→): Promise<{ proposed: boolean }> {
552→  const classification = await classifyRootCause(model, cluster, existingLearnings);
553→
554→  if (!classification) {
555→    // LLM call failed -- skip this cluster silently
556→    return { proposed: false };
557→  }
558→
559→  if (shouldProposeLearning(classification)) {
560→    const learningInput = rootCauseToLearningInput(classification, cluster);
561→
562→    // Generate embedding for the proposed learning text to enable
563→    // dismissed similarity gate and persist with the learning record
564→    const embedding = embeddingModel && embeddingDimension
565→      ? await createEmbeddingVector(embeddingModel, learningInput.text, embeddingDimension)
566→      : undefined;
567→
568→    const result = await suggestLearning({
569→      surreal,
570→      workspaceRecord,
571→      learning: learningInput,
572→      embedding,
573→      now: new Date(),
574→    });
575→
576→    if (result.created) {
577→      logInfo("observer.learning.proposed", "Learning proposed from root cause analysis", {
578→        category: classification.category,
579→        confidence: classification.confidence,
580→        learningType: classification.proposed_learning_type,
581→        learningId: result.learningRecord.id,
582→      });
583→      return { proposed: true };
584→    }
585→
586→    logInfo("observer.learning.gate_blocked", "Learning proposal blocked by safety gate", {
587→      reason: result.reason,
588→    });
589→    return { proposed: false };
590→  }
591→
592→  // Dual gate failed: create an observation instead
593→  await createObservation({
594→    surreal,
595→    workspaceRecord,
596→    text: `Emerging pattern detected but root cause unclear (${classification.category}, confidence: ${classification.confidence.toFixed(2)}): ${classification.reasoning}`,
597→    severity: "info",
598→    sourceAgent: "observer_agent",
599→    observationType: "pattern",
600→    now: new Date(),
601→  });
602→
603→  logInfo("observer.learning.low_confidence", "Pattern observed but confidence too low for learning proposal", {
604→    category: classification.category,
605→    confidence: classification.confidence,
606→    shouldPropose: classification.should_propose_learning,
607→  });
608→
609→  return { proposed: false };
610→}
611→
612→// ---------------------------------------------------------------------------
613→// Diagnostic pipeline orchestrator
614→// ---------------------------------------------------------------------------
615→
616→/**
617→ * Runs the observation clustering, coverage check, and root cause classification pipeline.
618→ *
619→ * Pipeline:
620→ * 1. Query recent observations with embeddings
621→ * 2. Cluster by pairwise similarity
622→ * 3. For each cluster, check coverage against active learnings
623→ * 4. For uncovered clusters, classify root cause via LLM
624→ * 5. Propose learning or create observation based on dual gate
625→ */
626→export async function runDiagnosticClustering(
627→  surreal: Surreal,
628→  workspaceRecord: RecordId<"workspace", string>,
629→  observerModel?: LanguageModel,
630→  embeddingModel?: EmbeddingModel,
631→  embeddingDimension?: number,
632→): Promise<{
633→  clusters: ObservationCluster[];
634→  uncoveredClusters: ObservationCluster[];
635→  result: DiagnosticResult;
636→}> {
637→  const diagnosticResult: DiagnosticResult = {
638→    learning_proposals_created: 0,
639→    coverage_skips: 0,
640→    clusters_found: 0,
641→  };
642→
643→  // Step 1: Query recent observations
644→  const observations = await queryRecentObservationsWithEmbeddings(
645→    surreal,
646→    workspaceRecord,
647→  );
648→
649→  if (observations.length < MINIMUM_CLUSTER_SIZE) {
650→    return { clusters: [], uncoveredClusters: [], result: diagnosticResult };
651→  }
652→
653→  // Step 2: Cluster by similarity (pure)
654→  const clusters = clusterObservationsBySimilarity(observations);
655→  diagnosticResult.clusters_found = clusters.length;
656→
657→  if (clusters.length === 0) {
658→    return { clusters: [], uncoveredClusters: [], result: diagnosticResult };
659→  }
660→
661→  // Step 3: Coverage check for each cluster
662→  const uncoveredClusters: ObservationCluster[] = [];
663→
664→  for (const cluster of clusters) {
665→    // Find the representative observation's embedding for coverage check
666→    const representativeObs = observations.find(
667→      (obs) => obs.text === cluster.representativeText,
668→    );
669→
670→    if (!representativeObs) {
671→      // Should not happen, but handle gracefully
672→      uncoveredClusters.push(cluster);
673→      continue;
674→    }
675→
676→    const coverage = await checkCoverageAgainstActiveLearnings(
677→      surreal,
678→      workspaceRecord,
679→      representativeObs.embedding,
680→    );
681→
682→    if (coverage.covered) {
683→      logInfo("observer.learning.coverage_skip", "Cluster pattern already covered by active learning", {
684→        clusterSize: cluster.clusterSize,
685→        matchedLearningText: coverage.matchedLearningText,
686→        similarity: coverage.similarity,
687→      });
688→      diagnosticResult.coverage_skips += 1;
689→      continue;
690→    }
691→
692→    // Check if a dismissed learning already covers this pattern
693→    const dismissedCheck = await checkDismissedLearningForCluster(
694→      surreal,
695→      workspaceRecord,
696→      representativeObs.embedding,
697→    );
698→
699→    if (dismissedCheck.covered) {
700→      logInfo("observer.learning.dismissed_skip", "Cluster pattern matches a previously dismissed learning", {
701→        clusterSize: cluster.clusterSize,
702→        matchedLearningText: dismissedCheck.matchedLearningText,
703→        similarity: dismissedCheck.similarity,
704→      });
705→      diagnosticResult.coverage_skips += 1;
706→    } else {
707→      uncoveredClusters.push(cluster);
708→    }
709→  }
710→
711→  // Step 4: Root cause classification for uncovered clusters (requires observer model)
712→  if (observerModel && uncoveredClusters.length > 0) {
713→    const existingLearnings = await queryActiveLearningTexts(surreal, workspaceRecord);
714→
715→    for (const cluster of uncoveredClusters) {
716→      const { proposed } = await processUncoveredCluster(
717→        surreal,
718→        workspaceRecord,
719→        observerModel,
720→        cluster,
721→        existingLearnings,
722→        embeddingModel,
723→        embeddingDimension,
724→      );
725→
726→      if (proposed) {
727→        diagnosticResult.learning_proposals_created += 1;
728→      }
729→    }
730→  }
731→
732→  return { clusters, uncoveredClusters, result: diagnosticResult };
733→}
734→

